const __pageData = JSON.parse('{"title":"About Agent Ruler","description":"","frontmatter":{"title":"About Agent Ruler"},"headers":[],"relativePath":"guides/about-agent-ruler.md","filePath":"guides/about-agent-ruler.md"}');
